import{_ as t,C as i,o as r,c as E,a2 as e,E as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Sandbox 笔记：代码执行不能碰宿主环境","description":"","frontmatter":{},"headers":[],"relativePath":"agent/sandbox-notes.md","filePath":"agent/sandbox-notes.md","lastUpdated":1782915681000}'),n={name:"agent/sandbox-notes.md"};function d(s,a,A,p,B,c){const o=i("Mermaid");return r(),E("div",null,[a[0]||(a[0]=e('<h1 id="sandbox-笔记-代码执行不能碰宿主环境" tabindex="-1">Sandbox 笔记：代码执行不能碰宿主环境 <a class="header-anchor" href="#sandbox-笔记-代码执行不能碰宿主环境" aria-label="Permalink to &quot;Sandbox 笔记：代码执行不能碰宿主环境&quot;">​</a></h1><p>代码执行是 Agent 里最有吸引力的能力之一。它能处理文件、生成图表、转换文档、分析数据，也能让 Agent 从“会说”变成“会做”。</p><p>但这也是风险最高的能力之一。模型生成的代码不可信，用户上传的文件不可信，外部依赖不可信。如果这些代码直接在宿主环境跑，风险不是 bug，而是安全事故。</p><p>我的底线很简单：没有沙箱，就不要执行代码。</p><h2 id="早期诱惑-本地直接跑" tabindex="-1">早期诱惑：本地直接跑 <a class="header-anchor" href="#早期诱惑-本地直接跑" aria-label="Permalink to &quot;早期诱惑：本地直接跑&quot;">​</a></h2><p>最方便的做法，是在服务端开临时目录，直接跑 Python 或 Node。开发时非常舒服，调试快，产物也容易看。</p><p>但这个方案的问题很明显：</p><ul><li>临时目录不等于隔离。</li><li>进程超时不等于资源受控。</li><li>默认网络开放风险很高。</li><li>依赖安装可能污染环境。</li><li>用户文件和输出文件边界不清。</li><li>session 复用可能带来状态污染。</li></ul><p>文档、表格、PDF 这些任务还依赖字体、转换工具、图像库、系统包。开发机能跑，不代表线上能跑。</p><h2 id="更稳的沙箱链路" tabindex="-1">更稳的沙箱链路 <a class="header-anchor" href="#更稳的沙箱链路" aria-label="Permalink to &quot;更稳的沙箱链路&quot;">​</a></h2>',10)),l(o,{code:"flowchart%20TD%0A%20%20%20%20Request%5B%22%E4%BB%A3%E7%A0%81%E6%89%A7%E8%A1%8C%E8%AF%B7%E6%B1%82%22%5D%20--%3E%20Provider%7B%22%E6%98%AF%E5%90%A6%E6%9C%89%20Sandbox%20Provider%22%7D%0A%20%20%20%20Provider%20--%20%22%E5%90%A6%22%20--%3E%20Reject%5B%22%E6%8B%92%E7%BB%9D%E6%89%A7%E8%A1%8C%EF%BC%8C%E4%B8%8D%E6%9C%AC%E5%9C%B0%E9%99%8D%E7%BA%A7%22%5D%0A%20%20%20%20Provider%20--%20%22%E6%98%AF%22%20--%3E%20Session%5B%22%E5%88%9B%E5%BB%BA%20%2F%20%E5%A4%8D%E7%94%A8%20Session%22%5D%0A%20%20%20%20Session%20--%3E%20Upload%5B%22%E4%B8%8A%E4%BC%A0%E8%BE%93%E5%85%A5%E6%96%87%E4%BB%B6%E5%92%8C%E5%BF%85%E8%A6%81%E8%B5%84%E4%BA%A7%22%5D%0A%20%20%20%20Upload%20--%3E%20Contract%5B%22%E8%BF%90%E8%A1%8C%E6%97%B6%E5%A5%91%E7%BA%A6%E6%A3%80%E6%9F%A5%22%5D%0A%20%20%20%20Contract%20--%3E%20Execute%5B%22%E6%89%A7%E8%A1%8C%E4%BB%A3%E7%A0%81%22%5D%0A%20%20%20%20Execute%20--%3E%20Collect%5B%22%E5%8F%AA%E6%94%B6%E9%9B%86%E8%BE%93%E5%87%BA%E7%9B%AE%E5%BD%95%22%5D%0A%20%20%20%20Collect%20--%3E%20Artifact%5B%22%E6%8C%81%E4%B9%85%E5%8C%96%E4%BA%A7%E7%89%A9%22%5D%0A%20%20%20%20Execute%20--%3E%20Cancel%7B%22%E5%8F%96%E6%B6%88%20%2F%20%E8%B6%85%E6%97%B6%22%7D%0A%20%20%20%20Cancel%20--%20%22%E8%A7%A6%E5%8F%91%22%20--%3E%20Cleanup%5B%22%E7%BB%88%E6%AD%A2%E6%89%A7%E8%A1%8C%20%2F%20%E6%B8%85%E7%90%86%20Session%22%5D%0A"}),a[1]||(a[1]=e('<p>这里最重要的是“不本地降级”。没有 provider 时，宁可返回不可用，也不要偷偷在宿主机器跑。</p><p>文件系统要有契约：输入放哪里，工作目录在哪里，输出目录在哪里，哪些文件会被收集。否则模型把文件写得到处都是，最后不是收不到，就是收了不该收的。</p><p>运行时也要有 contract check。语言运行时、系统工具、字体、文档转换依赖，都应该尽早检查。</p><h2 id="provider-能力不能假设一致" tabindex="-1">Provider 能力不能假设一致 <a class="header-anchor" href="#provider-能力不能假设一致" aria-label="Permalink to &quot;Provider 能力不能假设一致&quot;">​</a></h2><p>不同 provider 能力不同。有的支持网络策略，有的支持暂停恢复，有的能看资源指标，有的只提供基础执行。执行系统要基于 capability 判断，而不是想当然。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是没有沙箱 provider 时本地降级。这是最危险的便利。</p><p>第二个坑，是输出目录没有约束。模型生成的文件散落在不同路径，产物收集会变得不可控。</p><p>第三个坑，是 session 复用不清理。复用能省时间，但也可能让上一次任务残留影响下一次。</p><p>第四个坑，是没有 runtime contract。等用户任务失败才发现缺字体、缺转换工具，排查成本很高。</p><p>第五个坑，是把代码执行当普通工具。它是高风险工具，需要更强隔离、更严格审计。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果再做一次，我会更早做 warm pool，但配套资源配额和生命周期回收。</p><p>网络出站也应该放到基础设施层治理，不只依赖工具参数。产物只从约定输出目录收集，并且产物元数据要可审计。</p><p>一句话总结：代码解释器很有用，但它必须先进入可隔离、可销毁、可观察的运行环境。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么代码执行是 Agent 的高风险能力。</li><li>本地执行为什么不能作为默认路径。</li><li>沙箱文件系统契约应该怎么设计。</li><li>Runtime contract 为什么比事后报错重要。</li><li>Provider capability 为什么要显式声明。</li><li>Session 复用的收益和风险。</li><li>如果重做，我会怎样做 warm pool 和资源治理。</li></ol>',17))])}const u=t(n,[["render",d]]);export{_ as __pageData,u as default};
